def is_password_strong(password):
    if len(password) < 5:
        return False
    if not any(c.isupper() for c in password):
        return False
    if not any(c.islower() for c in password):
        return False
    if not any(c.isdigit() for c in password):
        return False
    return True

password = input().strip()
if is_password_strong(password):
    print("Correct")
else:
    print("Too weak")
